1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
12	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
13	
14	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
15	  sword: 1000,
16	  amulet: 600,
17	  staff: 800,
18	  potion: 400,
19	  rune: 250,
20	  moonstone: 250,
21	};
22	const COMPONENT_BASE_PRICE = 25;
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PRICE = 60;
25	
26	const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	const KNOWN_ITEM_TYPES = new Set<string>([
35	  ...Object.keys(BASE_PRICE_BY_ITEM_TYPE),
36	  ...COMPONENT_TYPES,
37	]);
38	
39	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
40	type Customer = { yearsWithMHPCO: number };
41	
42	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
43	
44	const isKnownItemType = (item: Item): boolean => KNOWN_ITEM_TYPES.has(item.type);
45	
46	const assertAllItemTypesKnown = (items: Item[]): void => {
47	  const unknown = items.find((item) => !isKnownItemType(item));
48	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
49	};
50	
51	const mainItemBasePrice = (item: Item): number =>
52	  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
53	
54	const componentGroupBasePrice = (count: number): number =>
55	  count === COMPONENT_BLOCK_SIZE
56	    ? COMPONENT_BLOCK_PRICE
57	    : count * COMPONENT_BASE_PRICE;
58	
59	const groupComponentsByType = (items: Item[]): Map<string, number> => {
60	  const groups = new Map<string, number>();
61	  for (const item of items) {
62	    if (!isComponent(item)) continue;
63	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
64	  }
65	  return groups;
66	};
67	
68	const sum = (numbers: number[]): number =>
69	  numbers.reduce((total, n) => total + n, 0);
70	
71	const policyBasePremium = (items: Item[]): number => {
72	  const mainItemPremiums = items
73	    .filter((item) => !isComponent(item))
74	    .map(mainItemBasePrice);
75	  const componentGroupPremiums = [...groupComponentsByType(items).values()].map(
76	    componentGroupBasePrice,
77	  );
78	  return sum([...mainItemPremiums, ...componentGroupPremiums]);
79	};
80	
81	const curseSurcharge = (item: Item): number =>
82	  item.cursed ? mainItemBasePrice(item) * CURSE_SURCHARGE_RATE : 0;
83	
84	const highEnchantmentSurcharge = (item: Item): number =>
85	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
86	    ? mainItemBasePrice(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
87	    : 0;
88	
89	const itemSurcharges = (items: Item[]): number =>
90	  sum(items.map((item) => curseSurcharge(item) + highEnchantmentSurcharge(item)));
91	
92	const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
93	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
94	    ? basePremium * LOYALTY_DISCOUNT_RATE
95	    : 0;
96	
97	type QuoteContext = { contractIndex?: number };
98	
99	const followUpDiscount = (
100	  context: QuoteContext,
101	  basePremium: number,
102	): number =>
103	  (context.contractIndex ?? 0) >= 1
104	    ? basePremium * FOLLOWUP_CONTRACT_DISCOUNT_RATE
105	    : 0;
106	
107	export const quote = (
108	  customer: Customer,
109	  items: Item[],
110	  context: QuoteContext = {},
111	): number => {
112	  assertAllItemTypesKnown(items);
113	  const basePremium = policyBasePremium(items);
114	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
115	  return Math.ceil(
116	    basePremium +
117	      firstInsuranceSurcharge -
118	      loyaltyDiscount(customer, basePremium) -
119	      followUpDiscount(context, basePremium) +
120	      itemSurcharges(items) +
121	      PROCESSING_FEE,
122	  );
123	};
124	
125	type Policy = { items: Item[] };
126	type Damage = { itemType: string; amount: number };
127	type Incident = { cause?: string; damages: Damage[] };
128	type ClaimResult = { payout: number; remainingCap: number };
129	
130	const policyInsuranceSum = (policy: Policy): number =>
131	  sum(policy.items.map((item) => INSURANCE_VALUE_BY_ITEM_TYPE[item.type] ?? 0));
132	
133	const policyCap = (policy: Policy): number =>
134	  policyInsuranceSum(policy) * CAP_MULTIPLIER;
135	
136	const findPolicyItem = (policy: Policy, itemType: string): Item | undefined =>
137	  policy.items.find((item) => item.type === itemType);
138	
139	const assertAllDamagesCovered = (policy: Policy, damages: Damage[]): void => {
140	  const uncovered = damages.find((damage) => !findPolicyItem(policy, damage.itemType));
141	  if (uncovered) {
142	    throw new Error(`Damage references item not in policy: ${uncovered.itemType}`);
143	  }
144	};
145	
146	const payoutRateForItem = (item: Item | undefined): number =>
147	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
148	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
149	    : 1;
150	
151	const payoutForDamage = (policy: Policy, damage: Damage): number => {
152	  const rate = payoutRateForItem(findPolicyItem(policy, damage.itemType));
153	  return Math.max(0, damage.amount * rate - DEDUCTIBLE);
154	};
155	
156	type QuoteStep = { op: "quote"; items: Item[] };
157	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
158	type ScenarioStep = QuoteStep | ClaimStep;
159	type Scenario = { customer: Customer; steps: ScenarioStep[] };
160	type QuoteResult = { premium: number };
161	type ScenarioStepResult = QuoteResult | ClaimResult;
162	type ScenarioOutcome = { results: ScenarioStepResult[] };
163	
164	const runQuoteStep = (customer: Customer, step: QuoteStep): QuoteResult => ({
165	  premium: quote(customer, step.items),
166	});
167	
168	const policyFromStep = (steps: ScenarioStep[], policyIndex: number): Policy => {
169	  const declaringStep = steps[policyIndex] as QuoteStep;
170	  return { items: declaringStep.items };
171	};
172	
173	const runClaimStep = (
174	  steps: ScenarioStep[],
175	  step: ClaimStep,
176	  paidByPolicy: Map<number, number>,
177	): ClaimResult => {
178	  const policy = policyFromStep(steps, step.policy);
179	  const alreadyPaid = paidByPolicy.get(step.policy) ?? 0;
180	  const result = claim(policy, step.incident, alreadyPaid);
181	  paidByPolicy.set(step.policy, alreadyPaid + result.payout);
182	  return result;
183	};
184	
185	export const runScenario = (scenario: Scenario): ScenarioOutcome => {
186	  const paidByPolicy = new Map<number, number>();
187	  const results: ScenarioStepResult[] = scenario.steps.map((step) =>
188	    step.op === "quote"
189	      ? runQuoteStep(scenario.customer, step)
190	      : runClaimStep(scenario.steps, step, paidByPolicy),
191	  );
192	  return { results };
193	};
194	
195	const assertAllDamageAmountsNonNegative = (damages: Damage[]): void => {
196	  const negative = damages.find((damage) => damage.amount < 0);
197	  if (negative) {
198	    throw new Error(`Damage amount must be non-negative: ${negative.amount}`);
199	  }
200	};
201	
202	export const claim = (
203	  policy: Policy,
204	  incident: Incident,
205	  alreadyPaid: number = 0,
206	): ClaimResult => {
207	  assertAllDamageAmountsNonNegative(incident.damages);
208	  assertAllDamagesCovered(policy, incident.damages);
209	  const remainingBefore = policyCap(policy) - alreadyPaid;
210	  const desiredPayout = sum(
211	    incident.damages.map((damage) => payoutForDamage(policy, damage)),
212	  );
213	  const payout = Math.min(desiredPayout, remainingBefore);
214	  const remainingCap = remainingBefore - payout;
215	  return { payout: Math.floor(payout), remainingCap };
216	};
